patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..2a345dd4f9ae 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3344,6 +3344,13 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else if (C.isOne()) {
+      // icmp eq (add (zext A), (zext B)), 1 --> icmp eq (xor A, B), 1 (i.e., xor A, B if 1 bit)
+      Value *A, *B;
+      if (match(BOp0, m_ZExt(m_Value(A))) && match(BOp1, m_ZExt(m_Value(B))) &&
+          A->getType()->isIntOrIntVectorTy(1) && B->getType()->isIntOrIntVectorTy(1)) {
+        return replaceInstUsesWith(Cmp, Builder.CreateXor(A, B));
+      }
     }
     break;
   }

